sys_script_email.script:
(function runMailScript( /* GlideRecord */ current, /* TemplatePrinter */ template,
    /* Optional EmailOutbound */
    email, /* Optional GlideRecord */ email_action,
    /* Optional GlideRecord */
    event) {
    var eventName = event.getValue("name");
    var orgName = null;
    var attributes = null;

    if (
        eventName === Constants.EVENT.requestRejected ||
        eventName === Constants.EVENT.certificateGenerated ||
        eventName === Constants.EVENT.certificateFailed ||
        eventName === Constants.EVENT.certificateDelayed ||
        eventName === Constants.EVENT.certificateFailedAdmin
    ) {
        attributes = JSON.parse(current.getValue("attributes"));
    } else {
        var document_id = current.getValue("document_id");
        var gr = new GlideRecord(Constants.CERTIFICATE_REQUEST.table);
        gr.get(document_id);
        attributes = JSON.parse(gr.getValue("attributes"));
    }

    orgName = attributes.subject.organization_name || "—";

    template.print(
        '<div class="insideBoxCell" style="margin-bottom: 20px;">' +
        '<p class="semi" style="font-size: 14px; margin: 0; margin-bottom: 5px; font-family: \'Roboto\', sans-serif; font-weight: 800; color: #333333;">Organization name</p>' +
        '<p class="greyText" style="font-family: \'Roboto\', sans-serif; font-size: 14px; font-weight: 400; margin: 0; margin-bottom: 5px; color: #666666;">' +
        orgName +
        '</p>' +
        '</div>'
    );

})(current, template, email, email_action, event);
